"use client";

import { Portal } from "@ark-ui/react";
import {
  ColorPicker as ArkColorPicker,
  parseColor as parseColorArk,
} from "@ark-ui/react/color-picker";
import { Pipette } from "lucide-react";
import type React from "react";
import { cn } from "@/lib/utils";

export const parseColor = parseColorArk;

export const ColorPicker = (
  props: React.ComponentProps<typeof ArkColorPicker.Root>
) => {
  const {
    lazyMount = true,
    unmountOnExit = true,
    className,
    children,
    ...rest
  } = props;

  return (
    <ArkColorPicker.Root
      className={cn(
        "flex w-full max-w-64 flex-col gap-2 text-foreground",
        className
      )}
      data-slot="color-picker"
      lazyMount={lazyMount}
      unmountOnExit={unmountOnExit}
      {...rest}
    >
      {children}

      <ArkColorPicker.HiddenInput />
    </ArkColorPicker.Root>
  );
};

export const ColorPickerControl = (
  props: React.ComponentProps<typeof ArkColorPicker.Control>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.Control
      className={cn("flex flex-row items-center gap-2", className)}
      data-slot="color-picker-control"
      {...rest}
    />
  );
};

export const ColorPickerTrigger = (
  props: React.ComponentProps<typeof ArkColorPicker.Trigger>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.Trigger
      className={cn(
        "grid min-h-10 min-w-10 shrink-0 cursor-pointer place-items-center overflow-hidden rounded-md border border-input bg-background p-0 outline-none",
        "focus-visible:border-primary focus-visible:ring-[1px] focus-visible:ring-primary",
        "data-disabled:opacity-50 data-disabled:grayscale",
        className
      )}
      data-slot="color-picker-trigger"
      {...rest}
    />
  );
};

export const ColorPickerChannelInput = (
  props: React.ComponentProps<typeof ArkColorPicker.ChannelInput>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.ChannelInput
      className={cn(
        "h-10 min-w-0 flex-1 rounded-md border border-input bg-transparent px-2 font-mono text-foreground text-sm outline-none transition-colors",
        "placeholder:text-muted-foreground",
        "focus:border-primary focus:ring-[1px] focus:ring-primary",
        "data-disabled:opacity-50",
        "[&[data-channel=alpha]]:w-16 [&[data-channel=alpha]]:min-w-0",
        "[appearance:textfield] [&::-webkit-inner-spin-button]:appearance-none [&::-webkit-outer-spin-button]:appearance-none",
        className
      )}
      data-slot="color-picker-channel-input"
      {...rest}
    />
  );
};

export const ColorPickerTransparencyGrid = (
  props: React.ComponentProps<typeof ArkColorPicker.TransparencyGrid>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.TransparencyGrid
      className={cn(
        "col-start-1 row-start-1 size-full rounded-[inherit]",
        "[background-image:linear-gradient(45deg,#e4e4e4_25%,transparent_25%),linear-gradient(-45deg,#e4e4e4_25%,transparent_25%),linear-gradient(45deg,transparent_75%,#e4e4e4_75%),linear-gradient(-45deg,transparent_75%,#e4e4e4_75%)]",
        "[background-position:0_0,0_4px,4px_-4px,-4px_0] [background-size:8px_8px]",
        "dark:[background-image:linear-gradient(45deg,#404040_25%,transparent_25%),linear-gradient(-45deg,#404040_25%,transparent_25%),linear-gradient(45deg,transparent_75%,#404040_75%),linear-gradient(-45deg,transparent_75%,#404040_75%)]",
        className
      )}
      {...rest}
    />
  );
};

export const ColorPickerValueSwatch = (
  props: React.ComponentProps<typeof ArkColorPicker.ValueSwatch>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.ValueSwatch
      className={cn(
        "z-1 col-start-1 row-start-1 size-full rounded-[inherit]",
        className
      )}
      {...rest}
    />
  );
};

export const ColorPickerPositioner = (
  props: React.ComponentProps<typeof ArkColorPicker.Positioner>
) => {
  const { className, ...rest } = props;
  return (
    <ArkColorPicker.Positioner
      className={cn(className)}
      data-slot="color-picker-positioner"
      {...rest}
    />
  );
};

export const ColorPickerContent = (
  props: React.ComponentProps<typeof ArkColorPicker.Content>
) => {
  const { className, ...rest } = props;

  return (
    <Portal>
      <ColorPickerPositioner>
        <ArkColorPicker.Content
          className={cn(
            "relative flex w-64 flex-col gap-3 rounded-lg border bg-popover p-4 shadow-md outline-none",
            "data-[state=open]:fade-in-0 data-[state=open]:zoom-in-95 data-[state=open]:animate-in",
            "data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95 data-[state=closed]:animate-out",
            className
          )}
          data-slot="color-picker-content"
          {...rest}
        />
      </ColorPickerPositioner>
    </Portal>
  );
};

export const ColorPickerArea = (
  props: React.ComponentProps<typeof ArkColorPicker.Area>
) => {
  const { className, ...rest } = props;
  return (
    <ArkColorPicker.Area
      className={cn(
        "relative h-40 touch-none overflow-hidden rounded-md",
        className
      )}
      data-slot="color-picker-area"
      {...rest}
    />
  );
};

export const ColorPickerAreaBackground = (
  props: React.ComponentProps<typeof ArkColorPicker.AreaBackground>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.AreaBackground
      className={cn(className)}
      data-slot="color-picker-area-background"
      {...rest}
    />
  );
};

export const ColorPickerAreaThumb = (
  props: React.ComponentProps<typeof ArkColorPicker.AreaThumb>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.AreaThumb
      className={cn(
        "size-3 -translate-x-1/2 -translate-y-1/2 rounded-full shadow-[0_0_0_2px_white,0_0_0_3px_rgba(0,0,0,0.1),0_1px_3px_rgba(0,0,0,0.15)] outline-none",
        "focus-visible:shadow-[0_0_0_2px_white,0_0_0_4px_hsl(var(--primary)),0_1px_3px_rgba(0,0,0,0.15)]",
        className
      )}
      data-slot="color-picker-area-thumb"
      {...rest}
    />
  );
};

export const ColorPickerChannelSlider = (
  props: React.ComponentProps<typeof ArkColorPicker.ChannelSlider>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.ChannelSlider
      className={cn("relative h-2.5 flex-1 rounded-sm", className)}
      data-slot="color-picker-channel-slider"
      {...rest}
    />
  );
};

export const ColorPickerChannelSliderTrack = (
  props: React.ComponentProps<typeof ArkColorPicker.ChannelSliderTrack>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.ChannelSliderTrack
      className={cn("size-full rounded-sm", className)}
      {...rest}
    />
  );
};

export const ColorPickerChannelSliderThumb = (
  props: React.ComponentProps<typeof ArkColorPicker.ChannelSliderThumb>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.ChannelSliderThumb
      className={cn(
        "size-3 -translate-x-1/2 -translate-y-1/2 rounded-full shadow-[0_0_0_2px_white,0_0_0_3px_rgba(0,0,0,0.1),0_1px_3px_rgba(0,0,0,0.15)] outline-none",
        "focus-visible:shadow-[0_0_0_2px_white,0_0_0_4px_hsl(var(--primary)),0_1px_3px_rgba(0,0,0,0.15)]",
        className
      )}
      {...rest}
    />
  );
};

export const ColorPickerEyeDropperTrigger = (
  props: React.ComponentProps<typeof ArkColorPicker.EyeDropperTrigger>
) => {
  const { className, children, ...rest } = props;

  return (
    <ArkColorPicker.EyeDropperTrigger
      className={cn(
        "flex size-10 shrink-0 cursor-pointer items-center justify-center rounded-md border border-input bg-transparent text-foreground outline-none transition-colors",
        "hover:bg-muted",
        "focus-visible:border-primary focus-visible:ring-[1px] focus-visible:ring-primary",
        className
      )}
      data-slot="color-picker-eye-dropper"
      {...rest}
    >
      {children || <Pipette className="size-4" />}
    </ArkColorPicker.EyeDropperTrigger>
  );
};

export const ColorPickerHiddenInput = (
  props: React.ComponentProps<typeof ArkColorPicker.HiddenInput>
) => {
  const { className, ...rest } = props;
  return <ArkColorPicker.HiddenInput className={cn(className)} {...rest} />;
};
